func trackHandler(w http.ResponseWriter, r *http.Request) {
	start := time.Now()

	user := r.URL.Query().Get("user")
	if user == "" {
		user = "anonymous"
	}
	requestID := r.URL.Query().Get("request_id")
	if requestID == "" {
		requestID = strconv.FormatInt(time.Now().UnixNano(), 10)
	}
	event := r.URL.Query().Get("event")
	if event == "" {
		event = "default"
	}
	path := r.URL.Path
	method := r.Method

	activeRequests.WithLabelValues(user, path).Inc()
	defer activeRequests.WithLabelValues(user, path).Dec()

	status := http.StatusOK
	defer func() {
		requestsTotal.WithLabelValues(user, requestID, method, path, strconv.Itoa(status)).Inc()
		requestDuration.WithLabelValues(user, requestID, method, path).Observe(time.Since(start).Seconds())
		userEvents.WithLabelValues(user, event).Inc()
	}()

	w.Header().Set("Content-Type", "text/plain; charset=utf-8")
	w.WriteHeader(status)
	_, _ = w.Write([]byte("tracked\n"))
}

